SELECT id, title FROM lesson WHERE id IN (151,152,153,154) ORDER BY id;
-- 2. Quiz-Träger auf Seite 4:
SELECT id, page_number, order_index, content_type FROM lesson_content WHERE lesson_id=153 AND page_number=4 ORDER BY order_index;  -- → id 6433 (text)
-- 3. Fragen zur Findung:
SELECT id, order_index, question_text, explanation FROM quiz_question WHERE id IN (3622,3628);
-- 4. Optionen:
SELECT id, order_index, option_text, is_correct, feedback FROM quiz_option WHERE question_id IN (3622,3628) ORDER BY question_id, order_index;
-- 5. L153-Kana-Karten (Grundzeichen-Menge, Beleg dass ジ/ガ nicht dabei):
SELECT k.character, k.romanization FROM lesson_content lc JOIN kana k ON k.id=lc.content_id WHERE lc.lesson_id=153 AND lc.content_type='kana' ORDER BY lc.order_index;

-- Bloecke lokalisiert + Ist-Wert geholt:
