SELECT lc.page_number, lc.order_index, v.word, v.reading, v.meaning_de FROM lesson_content lc JOIN vocabulary v ON lc.content_id=v.id WHERE lc.lesson_id=165 AND lc.content_type='vocabulary' ORDER BY lc.page_number, lc.order_index;

